local _payload = (function()
    local KEY = {151,160,111,101,224,132,56,123,20,37,170,52,62,173,213,148,126,110,210,214,29,200,71,235}
    local DATA = ""
    local b64chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
    local lookup = {}
    for i = 1, #b64chars do lookup[b64chars:sub(i, i)] = i - 1 end
    local function b64dec(input)
        input = input:gsub("[^A-Za-z0-9+/]", "")
        local bytes = {}
        local n = 0
        for i = 1, #input, 4 do
            local c1 = lookup[input:sub(i, i)] or 0
            local c2 = lookup[input:sub(i + 1, i + 1)] or 0
            local c3 = lookup[input:sub(i + 2, i + 2)]
            local c4 = lookup[input:sub(i + 3, i + 3)]
            local b1 = c1 * 4 + math.floor(c2 / 16)
            n = n + 1; bytes[n] = string.char(b1)
            if c3 then
                local b2 = (c2 % 16) * 16 + math.floor(c3 / 4)
                n = n + 1; bytes[n] = string.char(b2)
                if c4 then
                    local b3 = (c3 % 4) * 64 + c4
                    n = n + 1; bytes[n] = string.char(b3)
                end
            end
        end
        return table.concat(bytes)
    end
    local _xor
    if bit32 and bit32.bxor then
        _xor = bit32.bxor
    else
        _xor = function(a, b)
            local r, p = 0, 1
            for _ = 1, 8 do
                local ab, bb = a % 2, b % 2
                if ab ~= bb then r = r + p end
                a = (a - ab) / 2
                b = (b - bb) / 2
                p = p * 2
            end
            return r
        end
    end
    local raw = b64dec(DATA)
    local out = {}
    local klen = #KEY
    for i = 1, #raw do
        out[i] = string.char(_xor(string.byte(raw, i), KEY[((i - 1) % klen) + 1]))
    end
    return table.concat(out)
end)()

local _fn, _err = (loadstring or load)(_payload, "@ProjectTheRake")
if not _fn then
    error("[ProjectTheRake] 加载失败: " .. tostring(_err))
end
return _fn()
